# --- Fetch Remote Dependencies ---
def fetch_remote_dependencies(url):
    """
    Fetches a list of dependencies from a remote URL.
    Assumes the remote file contains one package name per line.
    """
    print(f"Attempting to fetch remote dependencies from: {url}")
    try:
        with urllib.request.urlopen(url) as response:
            content = response.read().decode('utf-8')
        dependencies = [line.strip() for line in content.splitlines() if line.strip() and not line.strip().startswith('#')]
        print(f"Successfully fetched {len(dependencies)} remote dependencies.")
        return dependencies
    except urllib.error.URLError as e:
        print(f"Warning: Could not fetch remote dependencies from {url}. Error: {e}")
        print("Proceeding without remote dependencies. Please ensure network connectivity if these are critical.")
        return []
    except Exception as e:
        print(f"An unexpected error occurred while fetching remote dependencies: {e}")
        return []

